288	    // Data storage
289	    always_ff @(posedge clk) begin
290	        if(mask_i | use_reduce_tree_ex1) begin
291	            if(valid_int_ex1) begin
292	                data_ex1 <= res_int_ex1;
293	            end else if(valid_fp_ex1) begin
