    end else if (FWD_POINT_A == `EX2) begin :g_fwd_pnt_a_ex2
        assign frw_a_en_o   = ready_res_ex2 | ready_res_int_ex2 | ready_res_fp_ex2 | ready_res_fxp_ex2;
