    end else if (FWD_POINT_B == `EX3) begin :g_fwd_pnt_b_ex3
        assign frw_b_en_o   = ready_res_ex3 | ready_res_int_ex3 | ready_res_fp_ex3 | ready_res_fxp_ex3;
        assign frw_b_data_o = ~mask_ex3         ? '0                           :
                              ready_res_ex3     ? data_ex2[0    +: DATA_WIDTH] :
