    end endgenerate

    // Writeback Signals
    assign wr_en_o        = valid_result_wr;
    assign wr_data_o      = use_temp_rdc_result ? temp_rdc_result_ex4[0 +: DATA_WIDTH] & {DATA_WIDTH{mask_wr}} :
